class MyQueue:

    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    def push(self, x: int) -> None:
        self.stack1.append(x)

    def pop(self) -> int:
        if not self.empty():
            while len(self.stack1) > 1:
                self.stack2.append(self.stack1.pop())
            return self.stack1.pop()
        return None

    def peek(self) -> int:
        if not self.empty():
            while len(self.stack1) > 1:
                self.stack2.append(self.stack1.pop())
            return self.stack1[-1]
        return None

    def empty(self) -> bool:
        return len(self.stack1) == 0
